#include<bits/stdc++.h>
using namespace std;
long long a[100010],n;
long long s[1000010];
long long f[100010];
long long lowbit(long long x)
{
    return x&-x;
}
const long long mod=1e9+7;
void update(long long x,long long v)
{
    for(long long i=x;i<=n;i+=lowbit(i))
    {
        s[i]+=v;
        s[i]%=mod;
    }
}
long long query(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans+=s[i];
        ans%=mod;
    }
    return ans;
}
long long b[100010],lst[100010];
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        b[i]=a[i];
    }
    sort(b+1,b+1+n);
    long long m=unique(b+1,b+1+n)-b-1;
    for(long long i=1;i<=n;i++)
    {
        a[i]=lower_bound(b+1,b+1+m,a[i])-b;
    }
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        long long tmp=query(a[i]-1);
        if(!f[a[i]])
        {
            ans+=tmp;
            ans%=mod;
            update(a[i],tmp+1);
        }
        else
        {
            ans+=((tmp-lst[a[i]])%mod+mod)%mod;
            ans%=mod;
            update(a[i],((tmp-lst[a[i]])%mod+mod)%mod);
        }
        f[a[i]]=1;
        lst[a[i]]=tmp;
    }
    printf("%lld",ans%mod);
    return 0;
}
